use std::collections::BinaryHeap;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut adj = vec![vec![]; n];
    for e in edges {
        let u = e[0] as usize;
        let v = e[1] as usize;
        let cost = e[2];
        adj[u].push((v, cost));
    }

    let mut max_min = vec![i64::MIN; n];
    max_min[0] = i64::MAX;

    let mut heap = BinaryHeap::new();
    heap.push((-i64::MAX, 0, 0));

    while let Some((neg_curr_min, total_cost, u)) = heap.pop() {
        let curr_min = -neg_curr_min;
        if u == n - 1 {
            return curr_min;
        }
        if total_cost > k {
            continue;
        }
        if curr_min < max_min[u] {
            continue;
        }
        for (v, cost) in adj[u] {
            if !online[v] {
                continue;
            }
            let new_total = total_cost + cost;
            if new_total > k {
                continue;
            }
            let new_min = std::cmp::min(curr_min, cost);
            if new_min > max_min[v] {
                max_min[v] = new_min;
                heap.push((-new_min, new_total, v));
            }
        }
    }

    -1
}
