use std::collections::VecDeque;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len();
    let mut adj = vec![Vec::new(); n];
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        adj[u].push((v as i64, cost));
    }

    let mut in_degree = vec![0; n];
    for u in 0..n {
        for (v, _) in &adj[u] {
            in_degree[*v as usize] += 1;
        }
    }

    let mut queue = VecDeque::new();
    for i in 0..n {
        if in_degree[i] == 0 {
            queue.push_back(i);
        }
    }

    let mut top_order = Vec::new();
    while let Some(u) = queue.pop_front() {
        top_order.push(u);
        for (v, _) in &adj[u] {
            let v_idx = *v as usize;
            in_degree[v_idx] -= 1;
            if in_degree[v_idx] == 0 {
                queue.push_back(v_idx);
            }
        }
    }

    let mut max_edge = 0;
    for edge in &edges {
        let cost = edge[2];
        if cost > max_edge {
            max_edge = cost;
        }
    }

    let mut low = 0;
    let mut high = max_edge;
    let mut answer = -1;

    while low <= high {
        let mid = (low + high) / 2;
        let mut dist = vec![i64::MAX; n];
        dist[0] = 0;

        for &u in &top_order {
            if !online[u] {
                continue;
            }
            for (v, cost) in &adj[u] {
                let v_idx = *v as usize;
                if online[v_idx] && cost >= mid {
                    if dist[u] + cost < dist[v_idx] {
                        dist[v_idx] = dist[u] + cost;
                    }
                }
            }
        }

        if dist[n - 1] <= k {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    answer
}
