use std::collections::BinaryHeap;

fn solve(edges: Vec<Vec<i64>>, online: Vec<bool>, k: i64) -> i64 {
    let n = online.len() as i64;
    let mut adj = vec![vec![]; n as usize];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let cost = edge[2];
        adj[u].push((v, cost));
    }
    let mut best_min = vec![-i64::MAX; n as usize];
    let mut heap = BinaryHeap::new();

    for (v, cost) in adj[0].iter().cloned() {
        if online[v] && cost <= k {
            heap.push((-cost, cost, v as i64));
            best_min[v] = cost;
        }
    }

    while let Some((neg_min, total_cost, u)) = heap.pop() {
        let current_min = -neg_min;
        let u = u as usize;
        if current_min < best_min[u] {
            continue;
        }
        for (v, cost) in adj[u].iter().cloned() {
            if !online[v] {
                continue;
            }
            let new_total = total_cost + cost;
            if new_total > k {
                continue;
            }
            let new_min = std::cmp::min(current_min, cost);
            if new_min > best_min[v] {
                best_min[v] = new_min;
                heap.push((-new_min, new_total, v as i64));
            }
        }
    }

    if best_min[(n - 1) as usize] == -i64::MAX {
        -1
    } else {
        best_min[(n - 1) as usize]
    }
}
